INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ヒヨリでっす♪\n元気いっぱいがんばるよ♪", 1, 0, 1.4, "春咲 ひより", "ねぇねぇ、騎士クン\n手伝ってあげようよ～", 2, 0, 0, 1, 0, 0, 1001, "お！\nあそこに困ってそうな人発見！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("みんなみたいに\nわたしも強くならなきゃ", 1, 0, 1.4, "草野 優衣", "わ、わたし、\nなに言ってるんだろ\nあはは…", 2, 0, 0, 1, 0, 0, 1002, "大切な人を\n守れるようになりたい…って", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("フェンシングを始めてみては？", 1, 0, 1.4, "士条 怜", "少しは磨かれると思いますよ。", 2, 0, 0, 1, 0, 0, 1003, "キミに必要な集中力と感性が", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ねぇ、にいちゃん！", 1, 0, 1.5, "穂高 みそぎ", "みそぎはねぇ、\nかくれんぼやりたい！", 2, 0, 0, 1, 0, 0, 1004, "今日はなにして遊ぶ？", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("風宮あかりです", 1, 0, 1.4, "風宮 あかり", "私といっしょに…\nいかない？", 2, 0, 0, 1, 0, 0, 1006, "ねぇ…", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("出雲宮子なのー", 1, 0, 1.5, "出雲 宮子", "食べ物の恨みは怖いのー", 2, 0, 0, 1, 0, 0, 1007, "プリンたべたいのー", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ボクは虹村雪。", 1, 0, 1.4, "虹村 雪", "いいよ。\n見られることは運命さ…", 2, 0, 0, 1, 0, 0, 1008, "キミもボクの美貌に\n吸い寄せられたんだね。", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("フッ…聞いて後悔するがいい！", 1, 0, 1.4, "柊杏奈", "人呼んで「疾風の冥姫」!!", 2, 0, 0, 1, 0, 0, 1009, "我が真名は\nアンネローゼ・フォン・シュテッヒパルム！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("マホマホ王国のプリンセス、\nまほ姫どす", 1, 0, 1.5, "姫宮 真歩", "ほんまおおきにやわ～♪", 2, 0, 0, 1, 0, 0, 1010, "うさぎさん、\n運命の王子はんに巡りあわせてくれて", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("衣之咲璃乃です！", 1, 0, 1.4, "衣之咲 璃乃", "ここで会ったが\n100年目～！", 2, 0, 0, 1, 0, 0, 1011, "生き別れたお兄ちゃんを探して\n三千世界！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("私はハツネ、\n結構強いんだよ。\nきらーん☆", 1, 0, 1.4, "柏崎 初音", "…って、お願い！\n誰にも言わないでおいて～！", 2, 0, 0, 1, 0, 0, 1012, "ち、超能力って…\n何のことかな～？", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ちょす！\n美波鈴奈だよ～♪", 1, 0, 1.4, "美波 鈴奈", "ヒデサイまぢ\nGF（グッドフィーリング）～♪", 2, 0, 0, 1, 0, 0, 1016, "一応カリスマ読モJKやってまっす！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("はいたーい。\n喜屋武香織さー。", 1, 0, 1.4, "喜屋武 香織", "でも、沖縄もとってもいいとこさー", 2, 0, 0, 1, 0, 0, 1017, "東京は遊園地みたいなところさー", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("支倉伊緒です。", 1, 0, 1.4, "支倉 伊緒", "イオちゃんって呼んでね。", 2, 0, 0, 1, 0, 0, 1018, "先生って呼ばれるのは\nくすぐったいから", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ふえ…？\nミミ、むずかしいこと\nよくわかんない…", 1, 0, 1.5, "茜 ミミ", "ミミをおいてかないでぇ～", 2, 0, 0, 1, 0, 0, 1020, "あ！/\お兄ちゃ～ん\nまってよ～", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("あ…あの…えっと…\n栗…林…くるみ…です……", 1, 0, 1.5, "栗林 くるみ", "ふぇぇぇぇぇん……", 2, 0, 0, 1, 0, 0, 1021, "あの……\nふぇ……", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("風宮よりです。\nあああああ！", 1, 0, 1.4, "風宮 より", "なんてありがとうございます！", 2, 0, 0, 1, 0, 0, 1022, "こんな私に貴重な時間を\n割いていただき、", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("私、アヤネ！\nぷうきちと一緒についてってあげるね！", 1, 0, 1.5, "北条 綾音", "私こっち行きたいー\nね、早く早くー", 2, 0, 0, 1, 0, 0, 1023, "おにいちゃんどこいくの？\nえ？", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("わっ…わっ…私、\n天野すずめといいます！", 1, 0, 1.4, "天野 すずめ", "これて何か違う…\nあああすみません！", 2, 0, 0, 1, 0, 0, 1025, "ふ、不束者ですが\nどうぞ末永く…って、", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("……クスクス…私は\n…倉石恵理子……", 1, 0, 1.4, "倉石 恵理子", "離しませんわ………\n絶対に…!!", 2, 0, 0, 1, 0, 0, 1027, "あなたは…運命の……\n伴侶……", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("佐々木咲恋よ。\nねえ、世の中に無駄なことが\n多すぎると思わない？", 1, 0, 1.4, "佐々木 咲恋", "…そうでしょ？？", 2, 0, 0, 1, 0, 0, 1028, "その無駄を省くことができれば、\nもっと余裕のある暮らしができるっ！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("桜井望だよ！\nよろしくねっ", 1, 0, 1.4, "桜井 望", "あはは、\n私もまだまだだなぁ～", 2, 0, 0, 1, 0, 0, 1029, "ぇっと…\nキミ、私のこと知らないの?!", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("デケデケデンっ！", 1, 0, 1.4, "ニノン・ジュベール", "ショーグン、\nワタシと一緒に天下統一デース！", 2, 0, 0, 1, 0, 0, 1030, "初めまして、\n私はニノン・ジュベール申すデス！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("上喜しのぶです。\n手元のドクロが父です。", 1, 0, 1.4, "上喜 しのぶ", "おかしいですね……", 2, 0, 0, 1, 0, 0, 1031, "でもって私の隣にいるのが……\nえ、見えない？", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("目指すはビッグな\nお笑い芸人だっぺ！", 1, 0, 1.5, "野戸まひる", "そう、\nオラのボケに突っ込める相方が…！", 2, 0, 0, 1, 0, 0, 1033, "けんども\nそれには足りないモンが…", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("あの…私…綾瀬ゆかりです…\nあの…ごめんなさい！", 1, 0, 1.4, "綾瀬 ゆかり", "ちょ\nちょっと一杯飲んできます…！", 2, 0, 0, 1, 0, 0, 1034, "ちょっと緊張しちゃって…", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("氷川鏡華…です", 1, 0, 1.5, "氷川 鏡華", "これ以上お話しすることは…\nないです！", 2, 0, 0, 1, 0, 0, 1036, "知らない人とは話しちゃいけないので", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("柏崎…栞です。", 1, 0, 1.4, "柏崎 栞", "私体が弱いから、\n30分に一度休憩しないと\nいけないんです。", 2, 0, 0, 1, 0, 0, 1038, "……あ、アラーム。", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("ふ、双葉碧です。", 1, 0, 1.4, "双葉 碧", "野に咲く花が、\n唯一の話相手です。", 2, 0, 0, 1, 0, 0, 1040, "私、一人も友達がいなくて……", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("三角千歌です。", 1, 0, 1.4, "三角 千歌", "そう思っています。", 2, 0, 0, 1, 0, 0, 1042, "私の歌声で、\n皆さんが幸せになってくれたらいいなって…", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("安芸真琴だ。", 1, 0, 1.4, "安芸 真琴", "う、疑ってすまなかったな…", 2, 0, 0, 1, 0, 0, 1043, "あぁ？\nお前のそいつの仲間か？", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("わらわこそは夜を総べる者！", 1, 0, 1.4, "イリヤ・オーンスタイン", "わらわの偉大な力に\nひれ伏すがいい！\nはっはっは！", 2, 0, 0, 1, 0, 0, 1044, "生けとし生ける全ての者よ！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("そこで騎士は妖精を乱暴に……", 1, 0, 1.4, "遠見 空花", "ｌク、クウカに何かご用ですか!?", 2, 0, 0, 1, 0, 0, 1045, "ぐふふふふ……はっ！", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("宮坂たまきにゃ♪\n猫はいいにゃよ？", 1, 0, 1.4, "宮坂たまき", "う～ん…\n猫ってホントに最高にゃ～♪", 2, 0, 0, 1, 0, 0, 1046, "自由気ままで♪\n寝て遊んで、食べてケンカして…", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("大神美冬よ！", 1, 0, 1.4, "大神 美冬", "…と思ったら\nバイトの時間だ！\nまたあとでね！", 2, 0, 0, 1, 0, 0, 1048, "それでは早速クエストに…", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("星野静流だよ！", 1, 0, 1.4, "星野静流", "お姉ちゃんがぜ～んぶ\nやってあげるからね！", 2, 0, 0, 1, 0, 0, 1049, "クエストもバトルも\n掃除も洗濯も", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("アタシは玉泉美咲。", 1, 0, 1.5, "玉泉美咲", "学校では誰もが憧れる\nアイドル的な存在ってやつよ♪", 2, 0, 0, 1, 0, 0, 1050, "見ての通りの\nセクシー美少女で", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("？？？", 1, 0, 1.4, "リマ", "？？？？", 2, 0, 0, 1, 0, 0, 1052, "？？？？", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("モニカ・ヴァイスヴィントだ。", 1, 0, 1.5, "モニカ・ヴァイスヴィント", "そ、そこまでいうなら\nもらってやる", 2, 0, 0, 1, 0, 0, 1053, "菓子でつろうなどと\n稚拙な策を……", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("モニカ・ヴァイスヴィントだ。", 1, 0, 1.5, "ペコリーヌ", "そ、そこまでいうなら\nもらってやる", 2, 0, 0, 1, 0, 0, 1058, "菓子でつろうなどと\n稚拙な策を……", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("モニカ・ヴァイスヴィントだ。", 1, 0, 1.5, "コッコロ", "そ、そこまでいうなら\nもらってやる", 2, 0, 0, 1, 0, 0, 1059, "菓子でつろうなどと\n稚拙な策を……", 1);
INSERT INTO `v1_4661e3fbc3356d506a96250b1da3450849ef062f617ced56af5ef4c84a811565` VALUES ("モニカ・ヴァイスヴィントだ。", 1, 0, 1.5, "キャル", "そ、そこまでいうなら\nもらってやる", 2, 0, 0, 1, 0, 0, 1060, "菓子でつろうなどと\n稚拙な策を……", 1);
